var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"런던 안에 이렇게 깊은 숲이 있었다니…….","JPN":"ロンドンの中にこんな深い森があったなんて……","ENG":"I didn't know there was such a forest in London...","TWN":"倫敦竟然有這麼深的森林……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 여긴 어디죠?","JPN":"ここはいったいどこですか？","ENG":"Where are we?","TWN":"這到底是哪裡呀？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"여긴 런던이지만 동시에 런던이 아니라네.","JPN":"ここはロンドンではあるが、ロンドンではない。","ENG":"This is London, but also not at the same time.","TWN":"這裡是倫敦，但同時又不是倫敦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"런던이라는 땅 위에 <color=#ffd34c>어떤 세계</color>의 일부가 덮어 씌워진 것이지.","JPN":"ロンドンという地の上に<color=#ffd34c>とある世界</color>の一部が上書きされたのだ。","ENG":"A part of a <color=#ffd34c>certain world</color> has been overlaid on London.","TWN":"在名為倫敦的土地上，<color=#ffd34c>某個世界</color>的一部分被覆蓋了上去。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"두 세계의 위상이 서로 얽혀 있는 현상…….","JPN":"二つの世界の位相が絡み合っている現象……","ENG":"The phenomenon where two worlds intertwine...","TWN":"形成了兩個世界的位相相互交織的現象……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그자는 이걸 <color=#ffd34c>침식현상</color>이라고 하더군.","JPN":"あの者はこれを<color=#ffd34c>侵食現象</color>と呼んでいた。","ENG":"He called it the <color=#ffd34c>Counterside Effect</color>.","TWN":"那傢伙稱這為<color=#ffd34c>侵蝕現象</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그자라고요? 그 사람이 누구죠?","JPN":"あの者？　それは誰ですか？","ENG":"He? Who are you talking about?","TWN":"那個傢伙？他是誰？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 어떤 사건을 해결하는 과정에서 우연히 그자와 만나게 됐다네.","JPN":"私はある事件を解決する途中、偶然あの者と出会った。","ENG":"I happened to coincidentally meet him while on a case.","TWN":"他是我在解決某個案子的過程中偶然遇到的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그자는 자기 이름이 <color=#ffd34c>존 스미스</color>라고 했어.","JPN":"あの者は自分の名前を<color=#ffd34c>ジョン・スミス</color>と言っていたな。","ENG":"He said his name was <color=#ffd34c>John Smith</color>.","TWN":"那個人說他的名字是<color=#ffd34c>約翰·史密斯</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자기가 다른 세계로부터 이주해왔다고 주장하는 괴짜였지.","JPN":"自分は別の世界から移住してきたと主張する変わり者だったよ。","ENG":"He was an oddball who claimed that he was from another world.","TWN":"他是個怪人，聲稱自己是從另一個世界移居過來的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"다른 세계라고요?","JPN":"別の世界？","ENG":"Another world?","TWN":"另一個世界？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면, 이 세계 말고 다른 세계가 존재한다는 뜻인가요?","JPN":"それって、この世界以外にまた違う世界が存在してるってことですか？","ENG":"Then, there are other worlds besides this one?","TWN":"那麼，意思是這個世界之外還存在著其他的世界嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계에 마석이 발견된 지 얼마 지나지 않은 시점이었어.","JPN":"この世界で魔石が発見されて間もない時だった。","ENG":"It wasn't long after the discovery of Mana Stones.","TWN":"那是在這個世界發現魔石還沒多久的時候。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나와 파트너 역시 처음에는 그자의 말을 믿지 않았지.","JPN":"私とパートナーもまた、最初はあの者の言葉を信じていなかったんだ。","ENG":"My partner and I didn't believe him at first.","TWN":"我和搭檔一開始也不相信那傢伙的話。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 시간이 흐르고, 그동안 이 세계의 수많은 사건을 해결해 가면서…….","JPN":"だが時間が流れ、これまでこの世界の数多くの事件を解決しているうちに……","ENG":"But as time passed, and we solved countless cases...","TWN":"但隨著時間的推移，在解決了這個世界上的許多案件之後……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리는 우리의 이성과 상식 밖에 어떠한 <color=#ffd34c>세계의 법칙</color>이 존재한다는 것을 깨달았네.","JPN":"私たちは、我々の理性と常識の外にある<color=#ffd34c>世界の法則</color>が存在しているということに気付いた。","ENG":"We realized that a certain <color=#ffd34c>law of the world</color> existed that was beyond our understanding and common sense.","TWN":"我才意識到在我們的理性和常識之外，存在著某種<color=#ffd34c>世界的法則</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마석과 이능력자, 증표 그리고 평행 세계의 존재 역시 모두 세계의 법칙의 일부였지.","JPN":"魔石と異能力者、印、そしてパラレルワールドの存在もまたすべて、世界の法則の一部だった。","ENG":"Mana Stones, Supernaturals, marks, and existence of parallel worlds are all part of this law of the world.","TWN":"魔石與超能力者、印記以及平行世界的存在也都是世界法則的一部分。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면, 그 존 스미스라는 사람은 어디있죠? 그 사람에게 부탁한다면…….","JPN":"それなら、そのジョン・スミスって人はどこにいるんですか？　その人に頼めば……","ENG":"Then, where is this John Smith now? If we ask for his help...","TWN":"那麼，那位約翰·史密斯在哪裡呢？如果能拜託他的話……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그자는 이제 없네.","JPN":"あの者はもういない。","ENG":"He is no more.","TWN":"那個人已經不在了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그자가 알려준 유적이 있어. 우린 그곳으로 향하고 있는 거지.","JPN":"だがあの者が教えてくれた遺跡がある。私たちはそちらへ向かっているわけだ。","ENG":"But there is a ruin he told me about. And we are currently headed toward it.","TWN":"但是他告訴我們的遺跡還在。我們正要去那裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"유적이라고요?","JPN":"遺跡？","ENG":"A ruin?","TWN":"遺跡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_QM","text":{"KOREA":"그렇군. 이 세계를 벗어나려는 건가, 탐정?","JPN":"そうか。この世界から抜け出ようとしているのか、探偵。","ENG":"I see. Are you trying to escape this world, detective?","TWN":"原來如此。你是想離開這個世界嗎，偵探？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"하지만 그렇게 두지는 않을 거야.","JPN":"だが、そうはさせない。","ENG":"I can't allow that.","TWN":"但是我不能任由你那麼做。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"왜냐하면 왕께서 그걸 바라지 않으시거든.","JPN":"何故なら、王はそれをお望みではないからだ。","ENG":"Because the queen doesn't wish it.","TWN":"因為王不希望那樣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"카넬리안……?","JPN":"カーネリアン……？","ENG":"Carnelian...?","TWN":"卡內利安……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신은 죽었잖아요……? 어째서 마물이……? ","JPN":"あなたは死んだはずじゃ……？　どうして魔物に……？ ","ENG":"I saw you die... You've become a monster...?","TWN":"你不是死了嗎……？為什麼會變成怪物……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"왕께서 새로운 삶을 하사해 주셨기 때문이란다.","JPN":"王は私に新たな生を授けてくださった。","ENG":"The queen has given me a new life.","TWN":"因為王賜予了我新的生命。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_BOSS","text":{"KOREA":"그러니 너도 함께 우리의 자매가 되는 거야, 스완.","JPN":"だから、あんたも一緒に私たちの姉妹になるんだ、スワン。","ENG":"Swan, you will too become our sister.","TWN":"史旺，你也會成為我們的姐妹。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어……?","JPN":"えっ……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"큭, 어서 도망치게, 스완!!","JPN":"くっ、早く逃げたまえ、スワン！！","ENG":"Kgh. Run, Swan!!","TWN":"咳，快逃，史旺！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완 클레어……!!","JPN":"スワン・クレア……！！","ENG":"Swan Claire...!!","TWN":"史旺·克萊爾……！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};